sys_rest_message_fn.content:
{ 
	"query": "query sensorReading(
	$pageSize: Int
	$refreshCursor: Cursor
	$startCursor: Cursor
	$source: EndpointSource
	$filtersArray: [EndpointFieldFilter!]
) {
	endpoints(
		first: $pageSize
		filter: { filters: $filtersArray }
		refresh: $refreshCursor
		after: $startCursor
		source: $source
	) {
		collectionInfo {
			success
			active
			startCursor
			respondedPercentage
			respondedTotal
			contributedTotal
		}
		pageInfo {
			hasPreviousPage
			hasNextPage
			startCursor
			endCursor
		}
		edges {
			node {
				id
				sensorReadings(
					sensors: ${sensors_serialized}
				) {
					columns {
						name
						values
					}
				}
			}
		}
	}
}
",
	"variables": ${query_variables_object},
	"operationName": "sensorReading"
}
